(()=>{document.documentElement.classList.add("js-reveal");const els=document.querySelectorAll("[data-reveal]");if(!("IntersectionObserver"in window)){els.forEach((el)=>el.classList.add("in-view"));return;}
const io=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){entry.target.classList.add("in-view");io.unobserve(entry.target);}});},{rootMargin:"0px 0px -10% 0px"});els.forEach((el)=>io.observe(el));})();